"use client";

import React from "react";
import { motion } from "motion/react";
import { Currency } from "lucide-react";
import { spec } from "node:test/reporters";
import { updateForm } from "./formWizardStore";
import { useStateMachine } from "little-state-machine";

const OPTIONS = [
  {
    id: 1,
    group: "Managed",
    label: "Balanced",
    icon: (
      <img
        className="w-5 h-5"
        src="data:image/png;base64,"
      />
    ),
  },
  {
    id: 2,
    group: "Managed",
    label: "Growth",
    icon: (
      <img
        className="w-5 h-5"
        src="data:image/png;base64,"
      />
    ),
  },
  {
    id: 3,
    group: "Managed",
    label: "High Growth",
    icon: (
      <img
        className="w-5 h-5"
        src="data:image/png;base64,"
      />
    ),
  },
  {
    id: 4,
    group: "Managed",
    label: "High Growth Socially Conscious",
    icon: (
      <img
        className="w-5 h-5"
        src="data:image/png;base64,"
      />
    ),
  },
  {
    id: 5,
    group: "Index",
    label: "Indexed Balanced",
    icon: (
      <img
        className="w-5 h-5"
        src="data:image/png;base64,"
      />
    ),
  },
];

const Step3a_DefaultOption = ({ updateStep, ref }) => {
  const [selected, setSelected] = React.useState<number | null>(null);
  const { actions, state } = useStateMachine({ actions: { updateForm } });

  return (
    <div className="flex flex-col gap-8 w-[33rem] max-w-full" ref={ref}>
      {/* Heading */}
      <motion.h1
        initial={{ opacity: 0, y: -20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.6, ease: "easeOut" }}
        className="text-center font-bold text-xl"
      >
        Step 3: Select your option
      </motion.h1>

      {/* Options Container */}
      <div className="w-full bg-slate-100 rounded-[3rem] p-10 shadow-sm">
        <div className="flex flex-col gap-4">
          {OPTIONS.map((opt) => {
            const isSelected = selected === opt.id;

            opt.label;

            return (
              <motion.div
                key={opt.id}
                whileHover={{ y: -2 }}
                transition={{ duration: 0.1 }}
                className={`
                  cursor-pointer bg-white p-4 rounded-2xl border
                  flex items-center gap-4 shadow-sm transition-all
                  ${isSelected ? "border-teal-500 shadow-md" : "border-slate-200"}
                `}
                whileTap={{ scale: 0.95 }}
                onClick={() => setSelected(opt.id)}
              >
                {/* Icon Placeholder */}
                <div
                  className={`
                    p-3 rounded-lg transition-colors
                    ${isSelected ? "bg-teal-100" : "bg-orange-100"}
                  `}
                >
                  {opt.icon}
                </div>

                {/* Text */}
                <div className="flex flex-col">
                  <p className="text-[9px] text-slate-400 font-bold uppercase">
                    {opt.group}
                  </p>
                  <p className="text-slate-800 font-bold text-sm">
                    {opt.label}
                  </p>
                </div>

                {/* Tick */}
                {isSelected && (
                  <motion.div
                    initial={{ scale: 0 }}
                    animate={{ scale: 1 }}
                    className="ml-auto text-teal-600 font-bold text-lg"
                  >
                    ✓
                  </motion.div>
                )}
              </motion.div>
            );
          })}
        </div>
      </div>

      {/* Buttons */}
      <div className="flex justify-between">
        <button
          onClick={() => updateStep("StepTwo")}
          className="px-6 py-2 bg-slate-200 text-slate-800 rounded-lg font-bold transition hover:bg-slate-300"
        >
          Back
        </button>

        <button
          disabled={!selected}
          onClick={() => {
            updateStep("StepFour");
            actions.updateForm({
              option: OPTIONS.find((option) => option.id === selected)?.label,
            });
          }}
          className={`
            px-6 py-2 rounded-lg font-bold transition
            ${
              selected
                ? "bg-black text-white hover:-translate-y-1"
                : "bg-slate-300 text-slate-500 cursor-not-allowed"
            }
          `}
        >
          Continue
        </button>
      </div>
    </div>
  );
};

export default Step3a_DefaultOption;
